3	import type { Element } from '@bim-ai/core';
4	
5	import type { PlanProjectionPrimitivesV1Wire } from '../plan/planProjectionWire';
6	import {
7	  roofInspectorWireDiagnosticsLines,
8	  roofPlanWireRowForElement,
9	} from './roofAuthoringReadout';
10	
11	type RoofEl = Extract<Element, { kind: 'roof' }>;
12	
13	type Props = {
14	  selected: Element | undefined;
15	  elementsById: Record<string, Element>;
16	  wirePrimitives: PlanProjectionPrimitivesV1Wire | null;
17	  revision: number;
18	  onPersistProperty: (key: string, value: string) => void;
19	};
20	
21	export function RoofAuthoringWorkbench({
22	  selected,
23	  elementsById,
24	  wirePrimitives,
25	  revision,
26	  onPersistProperty,
27	}: Props) {
28	  const roof = selected?.kind === 'roof' ? (selected as RoofEl) : undefined;
29	
30	  const roofTypes = useMemo(() => {
31	    const rows = Object.values(elementsById).filter((e) => e.kind === 'roof_type');
32	    rows.sort((a, b) => a.id.localeCompare(b.id));
33	    return rows;
34	  }, [elementsById]);
35	
36	  const wireRow = useMemo(
37	    () => (roof ? roofPlanWireRowForElement(roof.id, wirePrimitives) : null),
38	    [roof, wirePrimitives],
39	  );
40	
41	  const diagLines = useMemo(() => roofInspectorWireDiagnosticsLines(wireRow), [wireRow]);
42	
43	  if (!roof) return null;
44	
45	  const rtVal = roof.roofTypeId && roofTypes.some((t) => t.id === roof.roofTypeId) ? roof.roofTypeId : '';
46	
47	  return (
48	    <div
49	      className="border-border mb-3 space-y-2 border-b pb-3 text-[11px]"
50	      data-testid="roof-authoring-workbench"
51	    >
52	      <div className="font-semibold text-muted">Roof type and geometry (replayable)</div>
53	      <label className="block text-[10px] text-muted">
54	        Roof type
55	        <select
56	          className="mt-1 w-full rounded border border-border bg-background px-2 py-1 text-[11px]"
57	          value={rtVal}
58	          key={`roof-rt-${roof.id}-${roof.roofTypeId ?? ''}-${revision}`}
59	          onChange={(e) => {
60	            onPersistProperty('roofTypeId', e.target.value);
61	          }}
62	        >
63	          <option value="">none</option>
64	          {roofTypes.map((t) => (
65	            <option key={t.id} value={t.id}>
66	              {t.name} ({t.id})
67	            </option>
68	          ))}
69	        </select>
70	      </label>
71	      <label className="block text-[10px] text-muted">
72	        Roof geometry mode
73	        <select
74	          className="mt-1 w-full rounded border border-border bg-background px-2 py-1 text-[11px]"
75	          value={roof.roofGeometryMode ?? 'mass_box'}
76	          key={`roof-rgm-${roof.id}-${roof.roofGeometryMode}-${revision}`}
77	          onChange={(e) => {
78	            onPersistProperty('roofGeometryMode', e.target.value);
79	          }}
80	        >
81	          <option value="mass_box">mass_box</option>
82	          <option value="gable_pitched_rectangle">gable_pitched_rectangle</option>
83	        </select>
