203	  const handleTabActivate = useCallback(
204	    (id: string) => {
205	      let pendingPlanCamera: ViewportSnapshot['planCamera'] | undefined;
206	
207	      setTabsState((s) => {
208	        if (s.activeId === id) return s;
209	        // Snapshot the outgoing tab's viewport state so it can be restored
210	        // when the user comes back. T-07.
211	        let snapshotted = s;
212	        if (s.activeId) {
213	          const outgoing = s.tabs.find((x) => x.id === s.activeId);
214	          if (outgoing) {
215	            if (outgoing.kind === '3d' || outgoing.kind === 'plan-3d') {
